candidate_sql:
SELECT 100.0 * SUM(CASE WHEN LOWER(c.colour) = 'blue' THEN 1 ELSE 0 END) / COUNT(*) AS percentage_blue_eyes
FROM superhero s
JOIN colour c ON c.id = s.eye_colour_id;

